from langflow.custom import Component
from langflow.io import MessageTextInput, DropdownInput, Output
from langflow.schema.message import Message
import json, csv, io

class StructuredDataParser(Component):
    display_name = "Autonomyx Structured Data Parser"
    description  = "Parse JSON, CSV, XML, YAML, HTML tables, Markdown tables from text input. Uses actual parser code — no LLM needed for structured formats."

    inputs = [
        MessageTextInput(name="raw_data", display_name="Raw Data / Text"),
        DropdownInput(name="format", display_name="Format",
            options=["auto-detect","json","csv","xml","yaml","html_tables","markdown_tables"],
            value="auto-detect"),
        MessageTextInput(name="extract_fields", display_name="Fields to Extract (optional)",
            placeholder="field1,field2 or leave empty for all"),
    ]
    outputs = [Output(name="parsed", display_name="Parsed JSON", method="parse")]

    def _detect(self, text: str) -> str:
        t = text.strip()
        if t.startswith("{") or t.startswith("["): return "json"
        if t.startswith("<"): return "xml"
        if t.startswith("---") or ":\n" in t: return "yaml"
        if "|" in t and "---" in t: return "markdown_tables"
        if "," in t.split("\n")[0]: return "csv"
        return "json"

    def parse(self) -> Message:
        raw   = self.raw_data.text if hasattr(self.raw_data, "text") else str(self.raw_data)
        fmt   = self.format if self.format != "auto-detect" else self._detect(raw)
        fields = [f.strip() for f in self.extract_fields.split(",") if f.strip()] if self.extract_fields else []

        try:
            if fmt == "json":
                data = json.loads(raw)
            elif fmt == "csv":
                reader = csv.DictReader(io.StringIO(raw))
                data = [row for row in reader]
            elif fmt == "markdown_tables":
                lines = [l for l in raw.strip().split("\n") if l.strip() and "---" not in l]
                if not lines: return Message(text=json.dumps({"error": "No table found"}))
                headers = [h.strip() for h in lines[0].split("|") if h.strip()]
                rows = []
                for line in lines[1:]:
                    vals = [v.strip() for v in line.split("|") if v.strip()]
                    if vals: rows.append(dict(zip(headers, vals)))
                data = rows
            else:
                data = {"raw": raw, "format": fmt, "note": "Install parser library for full support"}

            if fields and isinstance(data, list):
                data = [{f: row.get(f) for f in fields} for row in data]
            elif fields and isinstance(data, dict):
                data = {f: data.get(f) for f in fields}

            return Message(text=json.dumps({"format": fmt, "count": len(data) if isinstance(data, list) else 1, "data": data}, indent=2))
        except Exception as e:
            return Message(text=json.dumps({"error": str(e), "format": fmt}))
